-- ============================================================================
-- ПЕРСОНАЛЬНЫЕ SQL ЗАПРОСЫ ДЛЯ КАЖДОГО ЭКСПЕРТА
-- ============================================================================

-- ЕГОР ПЕТРОВ
SELECT
  (SELECT COUNT(*) FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_provedennoj_pervoj_vstreci) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров') as total_first_meetings,
  (SELECT COUNT(*) FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_provedennoj_vtoroj_vstreci) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров') as total_second_meetings,
  (SELECT COUNT(*) FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_naznacenia_pervoj_vstreci) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров') as total_appointed_meetings,
  (SELECT COUNT(*) FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_postanovki_broni) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров') as total_bookings,
  (SELECT COUNT(*) FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(CLSD) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров') as total_deals,
  (SELECT COUNT(*) FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_peredaci_v_OP) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Dengi_na_rukah >= 1000000 AND ID_statusa NOT IN (142, 143) AND Ima_otvetstvennogo = 'Егор Петров') as total_qualified_leads,
  (SELECT COUNT(*) FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_peredaci_v_OP) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров') as total_taken_leads,
  (SELECT COUNT(*) FROM Leads WHERE ID_voronki = 437595 AND CLSD IS NULL AND ID_statusa NOT IN (142, 143) AND Ima_otvetstvennogo = 'Егор Петров') as clients_in_work,
  (SELECT CONCAT('[', GROUP_CONCAT(CONCAT('{"name":"', Ima_otvetstvennogo, '","count":', cnt, '}') ORDER BY cnt DESC SEPARATOR ','), ']') FROM (SELECT Ima_otvetstvennogo, COUNT(*) as cnt FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_provedennoj_pervoj_vstreci) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров' GROUP BY Ima_otvetstvennogo HAVING cnt > 0 ORDER BY cnt DESC LIMIT 10) t) as first_meetings_json,
  (SELECT CONCAT('[', GROUP_CONCAT(CONCAT('{"name":"', Ima_otvetstvennogo, '","count":', cnt, '}') ORDER BY cnt DESC SEPARATOR ','), ']') FROM (SELECT Ima_otvetstvennogo, COUNT(*) as cnt FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_provedennoj_vtoroj_vstreci) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров' GROUP BY Ima_otvetstvennogo HAVING cnt > 0 ORDER BY cnt DESC LIMIT 10) t) as second_meetings_json,
  (SELECT CONCAT('[', GROUP_CONCAT(CONCAT('{"name":"', Ima_otvetstvennogo, '","count":', cnt, '}') ORDER BY cnt DESC SEPARATOR ','), ']') FROM (SELECT Ima_otvetstvennogo, COUNT(*) as cnt FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_naznacenia_pervoj_vstreci) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров' GROUP BY Ima_otvetstvennogo HAVING cnt > 0 ORDER BY cnt DESC LIMIT 10) t) as appointed_meetings_json,
  (SELECT CONCAT('[', GROUP_CONCAT(CONCAT('{"name":"', Ima_otvetstvennogo, '","count":', total_cnt, ',"paid":', paid_cnt, ',"free":', free_cnt, '}') ORDER BY total_cnt DESC SEPARATOR ','), ']') FROM (SELECT Ima_otvetstvennogo, COUNT(*) as total_cnt, SUM(CASE WHEN Bron = 'Платная' THEN 1 ELSE 0 END) as paid_cnt, SUM(CASE WHEN Bron = 'Бесплатная' THEN 1 ELSE 0 END) as free_cnt FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_postanovki_broni) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров' GROUP BY Ima_otvetstvennogo HAVING total_cnt > 0 ORDER BY total_cnt DESC LIMIT 10) t) as bookings_json,
  (SELECT CONCAT('[', GROUP_CONCAT(CONCAT('{"name":"', Ima_otvetstvennogo, '","count":', cnt, '}') ORDER BY cnt DESC SEPARATOR ','), ']') FROM (SELECT Ima_otvetstvennogo, COUNT(*) as cnt FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(CLSD) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров' GROUP BY Ima_otvetstvennogo HAVING cnt > 0 ORDER BY cnt DESC LIMIT 10) t) as deals_json,
  (SELECT CONCAT('[', GROUP_CONCAT(CONCAT('{"name":"', Ima_otvetstvennogo, '","count":', cnt, '}') ORDER BY cnt DESC SEPARATOR ','), ']') FROM (SELECT Ima_otvetstvennogo, COUNT(*) as cnt FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_peredaci_v_OP) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Dengi_na_rukah >= 1000000 AND ID_statusa NOT IN (142, 143) AND Ima_otvetstvennogo = 'Егор Петров' GROUP BY Ima_otvetstvennogo HAVING cnt > 0 ORDER BY cnt DESC LIMIT 10) t) as qualified_leads_json,
  (SELECT CONCAT('[', GROUP_CONCAT(CONCAT('{"name":"', Ima_otvetstvennogo, '","count":', cnt, '}') ORDER BY cnt DESC SEPARATOR ','), ']') FROM (SELECT Ima_otvetstvennogo, COUNT(*) as cnt FROM Leads WHERE ID_statusa IN (13612293, 19143580, 13561017, 19929904, 18954874, 19929910, 74869522, 13560963, 14523646, 75808062, 13560972, 17927590, 13560981, 13560966, 49345819, 13560999, 14338762, 13561008, 142, 143) AND DATE(Data_peredaci_v_OP) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND Ima_otvetstvennogo = 'Егор Петров' GROUP BY Ima_otvetstvennogo HAVING cnt > 0 ORDER BY cnt DESC LIMIT 10) t) as taken_leads_json;

